import React, { useEffect } from 'react';
import { Swiper, SwiperSlide } from 'swiper/react';
import { Pagination, Autoplay } from 'swiper/modules';
import 'swiper/css';
import 'swiper/css/pagination';
import styled from 'styled-components';
import AOS from 'aos';

const Section = styled.section`
  padding: 100px 10%;
  position: relative;
  overflow: hidden;
`;

const Header = styled.div`
  text-align: center;
  margin-bottom: 60px;

  h2 {
    font-size: 3rem;
    color: #00FFFF;
    margin-bottom: 20px;
    position: relative;
    display: inline-block;

    &::after {
      content: '';
      position: absolute;
      bottom: -10px;
      left: 50%;
      transform: translateX(-50%);
      width: 80px;
      height: 4px;
      background: linear-gradient(to right, #00FFFF, #00BFFF);
      border-radius: 2px;
    }
  }
`;

const SlideContent = styled.div`
  position: absolute;
  bottom: 0;
  left: 0;
  right: 0;
  padding: 20px;
  background: rgba(0, 0, 0, 0.7);
  color: white;
  text-align: left;

  h3 {
    font-size: 1.5rem;
    margin-bottom: 10px;
    color: #00FFFF;
  }

  p {
    font-size: 1rem;
    color: rgba(255, 255, 255, 0.9);
  }
`;

const StyledSwiper = styled(Swiper)`
  width: 100%;
  height: 500px;

  .swiper-slide {
    position: relative;
    
    img {
      width: 100%;
      height: 100%;
      object-fit: cover;
      border-radius: 15px;
    }
  }

  .swiper-pagination-bullet {
    background: #00FFFF;
  }
`;

const Gallery = () => {
  useEffect(() => {
    AOS.init({
      duration: 1000,
      once: true
    });
  }, []);

  const slides = [
    {
      image: require('../assets/IMG_0358.jpg'),
      title: 'Annual Hackathon',
      description: 'Students collaborating and innovating in our biggest event of the year'
    },
    {
      image: require('../assets/IMG_4972.jpg'),
      title: 'Tech Workshops',
      description: 'Hands-on learning sessions with industry experts'
    },
    {
      image: require('../assets/IMG_5760.jpeg'),
      title: 'Team Projects',
      description: 'Collaborative projects bringing ideas to life'
    },
    {
      image: require('../assets/IMG_0338.jpg'),
      title: 'Community Events',
      description: 'Building connections and sharing knowledge'
    }
  ];

  return (
    <Section>
      <Header>
        <h2 data-aos="fade-up">Optimus in Action</h2>
      </Header>

      <StyledSwiper
        modules={[Pagination, Autoplay]}
        pagination={{ clickable: true }}
        autoplay={{
          delay: 5000,
          disableOnInteraction: false,
        }}
        loop={true}
      >
        {slides.map((slide, index) => (
          <SwiperSlide key={index}>
            <img src={slide.image} alt={slide.title} />
            <SlideContent>
              <h3>{slide.title}</h3>
              <p>{slide.description}</p>
            </SlideContent>
          </SwiperSlide>
        ))}
      </StyledSwiper>
    </Section>
  );
};

export default Gallery;
